var __rsEv={good:{label:"Доказова база",cls:"ev-good"},mixed:{label:"Попередні дані",cls:"ev-mixed"},none:{label:"Без доказів",cls:"ev-none"}};
var __rsCards=[{id:"co2-tolerance",cat:"breath",ev:"mixed",title:"Затримка дихання тренує толерантність до CO₂",text:"Дискомфорт у затримці — це реакція на вуглекислий газ, а не брак кисню.",body:["Бажання вдихнути виникає тоді, коли в крові зростає рівень CO₂, а не коли закінчується кисень. Хеморецептори реагують саме на вуглекислий газ. Тому тренована «толерантність до CO₂» дає відчуття спокою й контролю навіть тоді, коли тіло сигналізує дихати.","Це пояснює, чому з практикою затримки стають довшими: змінюється не обʼєм легень, а реакція нервової системи на дискомфорт."],points:["Позив вдихнути дає CO₂, не нестача кисню","Затримки тренують реакцію мозку на дискомфорт","Прогрес — це спокій, а не лише секунди"],src:[["Дослідження: тренування затримки та CO₂ (PubMed)","https://pubmed.ncbi.nlm.nih.gov/?term=breath-hold+training+CO2+chemoreflex"],["Wikipedia — Hypercapnia","https://en.wikipedia.org/wiki/Hypercapnia"]]},
{id:"wimhof-evidence",cat:"breath",ev:"mixed",title:"Метод Віма Хофа: що показують дослідження",text:"Є контрольовані дослідження, але вибірки малі, а ефекти короткочасні.",body:["У відомому дослідженні 2014 року учасники, навчені методу, змогли свідомо вплинути на запальну відповідь після введення ендотоксину. Це цікавий результат, але група була невеликою, тож узагальнювати рано.","Метод поєднує гіпервентиляцію, затримки й холод — кожен компонент діє по-своєму. Більшість користі досі пояснюється стресостійкістю та спокоєм, а не «надздібностями»."],points:["Дихай лише сидячи або лежачи","Ніколи не практикуй у воді чи за кермом","Малі вибірки — висновки попередні"],src:[["Kox et al., 2014 — PNAS","https://www.pnas.org/doi/10.1073/pnas.1322174111"],["Wikipedia — Wim Hof Method","https://en.wikipedia.org/wiki/Wim_Hof_Method"]]},
{id:"coherent-55",cat:"breath",ev:"mixed",title:"Когерентне дихання ~5.5 за хвилину",text:"Повільне дихання близько 5–6 циклів за хвилину підвищує варіабельність серцевого ритму.",body:["На частоті близько 0.1 Гц (приблизно 5.5 вдиху-видиху за хвилину) ритми серця й дихання входять у резонанс, і HRV помітно зростає. Це маркер гнучкості автономної нервової системи.","Практика проста й безпечна: рівні вдих і видих приблизно по 5–6 секунд, без напруження."],points:["Орієнтир — 5–6 дихань за хвилину","Підвищує варіабельність серцевого ритму","Підходить для щоденного заспокоєння"],src:[["Russo et al., 2017 — Breathe (огляд)","https://breathe.ersjournals.com/content/13/4/298"],["Wikipedia — Heart rate variability","https://en.wikipedia.org/wiki/Heart_rate_variability"]]},
{id:"long-exhale",cat:"breath",ev:"good",title:"Подовжений видих заспокоює",text:"Видих активує гальмівну гілку нервової системи, і пульс трохи сповільнюється.",body:["Під час видиху активність блукаючого нерва зростає, і серцевий ритм природно сповільнюється — це називають дихальною аритмією. Якщо видих довший за вдих, заспокійливий ефект сильніший.","Простий протокол: вдих на 4 рахунки, видих на 6. Кілька хвилин достатньо, щоб знизити збудження."],points:["Видих → активація парасимпатики","Роби видих довшим за вдих","Орієнтир: вдих 4 — видих 6"],src:[["Дослідження: повільне дихання й парасимпатика (PubMed)","https://pubmed.ncbi.nlm.nih.gov/?term=slow+breathing+parasympathetic+activity"],["Wikipedia — Vagal tone","https://en.wikipedia.org/wiki/Vagal_tone"]]},
{id:"physiological-sigh",cat:"breath",ev:"mixed",title:"Подвійний вдих-зітхання знімає напругу швидко",text:"Два вдихи підряд і довгий видих — найшвидший спосіб збити гострий стрес.",body:["«Фізіологічне зітхання» — це короткий другий довдих на піку вдиху, а потім повільний видих. Воно розправляє спалі альвеоли й ефективно виводить CO₂, швидко знижуючи збудження.","Це природний механізм — ми робимо так уві сні та після плачу. Свідомо 1–3 цикли часто достатньо."],points:["Вдих → ще короткий довдих → довгий видих","Працює за секунди, не хвилини","Зручно перед стресовою ситуацією"],src:[["Дослідження: циклічне зітхання й настрій (PubMed)","https://pubmed.ncbi.nlm.nih.gov/?term=cyclic+sighing+mood+arousal"],["Wikipedia — Sigh","https://en.wikipedia.org/wiki/Sigh"]]},
{id:"cold-bat",cat:"cold",ev:"mixed",title:"Холод і бура жирова тканина",text:"Регулярний холод активує буру жирову тканину, що спалює енергію заради тепла.",body:["На відміну від білого жиру, бура тканина виробляє тепло, спалюючи енергію. Холод її активує й може дещо збільшувати її кількість.","У людей ефект на загальний метаболізм помірний та індивідуальний. Холод корисний багатьма способами, але це не інструмент для швидкого схуднення."],points:["Бура тканина гріє тіло, спалюючи енергію","Холод її активує","Вплив на вагу — скромний"],src:[["van Marken Lichtenbelt et al., 2009 — NEJM","https://www.nejm.org/doi/full/10.1056/NEJMoa0808718"],["Wikipedia — Brown adipose tissue","https://en.wikipedia.org/wiki/Brown_adipose_tissue"]]},
{id:"cold-mood",cat:"cold",ev:"mixed",title:"Чому після холодного душу гарний настрій",text:"Холод різко підвищує норадреналін і дофамін — звідси бадьорість і ясність.",body:["Занурення в холод сильно підіймає рівень норадреналіну та дофаміну, і цей підйом тримається годинами. Саме тому після холоду зʼявляється чіткість і піднесення.","Дихай рівно й починай з кінцівок. Уникай різких затримок дихання в крижаній воді — спрацьовує рефлекс пірнальника."],points:["Норадреналін і дофамін ростуть надовго","Починай з кінцівок, дихай спокійно","Не затримуй дихання різко в холоді"],src:[["Дослідження: холод і катехоламіни (PubMed)","https://pubmed.ncbi.nlm.nih.gov/?term=cold+water+immersion+catecholamines"],["Wikipedia — Diving reflex","https://en.wikipedia.org/wiki/Diving_reflex"]]},
{id:"cold-resilience",cat:"cold",ev:"mixed",title:"Холод — це тренування стресостійкості",text:"Добровільний контрольований стрес вчить залишатися спокійним у дискомфорті.",body:["Холод — це керований стрес: тіло кричить «вийди», а ти лишаєшся спокійним і дихаєш рівно. Ця навичка самовладання переноситься й на інші ситуації.","Ключ — поступовість і регулярність, а не екстремальність. Кілька хвилин достатньо."],points:["Керований дискомфорт тренує самовладання","Регулярність важливіша за тривалість","Нарощуй поступово"],src:[["Buijze et al., 2016 — PLOS ONE","https://journals.plos.org/plosone/article?id=10.1371/journal.pone.0161749"],["Wikipedia — Cold shower","https://en.wikipedia.org/wiki/Cold_shower"]]},
{id:"contrast",cat:"cold",ev:"mixed",title:"Контраст: тепло й холод по черзі",text:"Чергування гарячого й холодного дає бадьорість і відчуття відновлення.",body:["Контрастні процедури (сауна/гаряча вода → холод) активно перемикають судини й нервову систему. Багато людей відзначають бадьорість і кращий настрій.","Доказова база радше про субʼєктивне самопочуття, ніж про конкретні «детокс»-ефекти. Завершуй холодом, якщо хочеш бадьорості, теплом — якщо розслаблення."],points:["Чергуй тепло й холод","Завершення холодом бадьорить","Гучних медичних обіцянок уникай"],src:[["Дослідження: контрастна терапія й відновлення (PubMed)","https://pubmed.ncbi.nlm.nih.gov/?term=contrast+water+therapy+recovery"],["Wikipedia — Hydrotherapy","https://en.wikipedia.org/wiki/Hydrotherapy"]]},
{id:"morning-light",cat:"sleep",ev:"good",title:"Світло вранці — головний регулятор сну",text:"Яскраве світло у перші години після пробудження налаштовує внутрішній годинник.",body:["Ранкове світло, особливо денне надворі, задає циркадний ритм: піднімає денну бадьорість і зміщує вечірню сонливість у потрібний бік. Це одна з найсильніших і найдешевших звичок для сну.","5–10 хвилин надворі вранці дають набагато більше люксів, ніж кімнатне освітлення, навіть у хмарну погоду."],points:["Лови денне світло у перші години","5–10 хвилин надворі — вже багато","Покращує і засинання ввечері"],src:[["Дослідження: ранкове світло й циркадний ритм (PubMed)","https://pubmed.ncbi.nlm.nih.gov/?term=morning+bright+light+circadian+phase"],["Wikipedia — Circadian rhythm","https://en.wikipedia.org/wiki/Circadian_rhythm"]]},
{id:"cool-room",cat:"sleep",ev:"good",title:"Прохолодна кімната — глибший сон",text:"Щоб заснути, тіло знижує внутрішню температуру; прохолода цьому допомагає.",body:["Засинання супроводжується падінням внутрішньої температури тіла. Прохолодна спальня (близько 18–19 °C) підтримує цей процес і покращує глибину сну.","Тепла ванна за годину до сну теж працює — після неї тіло активніше віддає тепло й охолоджується."],points:["Орієнтир спальні — близько 18–19 °C","Тіло має охолонути, щоб заснути","Тепла ванна перед сном допомагає через охолодження"],src:[["Дослідження: температура середовища й сон (PubMed)","https://pubmed.ncbi.nlm.nih.gov/?term=ambient+temperature+sleep"],["Wikipedia — Thermoregulation","https://en.wikipedia.org/wiki/Thermoregulation"]]},
{id:"sleep-consistency",cat:"sleep",ev:"good",title:"Стабільний час — недооцінена звичка",text:"Однаковий час підйому щодня стабілізує циркадний ритм сильніше за ґаджети.",body:["Регулярний час пробудження — навіть на вихідних — тримає внутрішній годинник у фазі. Це впливає на сон сильніше, ніж більшість «розумних» девайсів.","Сталість важливіша за ідеальну тривалість окремої ночі: одна недоспана ніч менш шкідлива, ніж постійний хаос у графіку."],points:["Прокидайся в один час щодня","Регулярність > ідеальна тривалість однієї ночі","Вихідні теж рахуються"],src:[["Дослідження: регулярність сну й здоровʼя (PubMed)","https://pubmed.ncbi.nlm.nih.gov/?term=sleep+regularity+health+outcomes"],["Wikipedia — Sleep hygiene","https://en.wikipedia.org/wiki/Sleep_hygiene"]]},
{id:"nsdr",cat:"sleep",ev:"mixed",title:"NSDR / йога-нідра для відновлення вдень",text:"Кероване розслаблення лежачи поповнює ресурс, навіть якщо ти не заснув.",body:["NSDR (non-sleep deep rest) — це спокійне лежання з керуванням увагою й диханням. Воно знижує збудження й допомагає відновитися, навіть без справжнього сну.","Зручний інструмент для денного перезавантаження або коли вночі недоспав. 10–20 хвилин зазвичай достатньо."],points:["Глибокий відпочинок без засинання","10–20 хвилин для перезавантаження","Альтернатива денному сну"],src:[["Дослідження: yoga nidra (PubMed)","https://pubmed.ncbi.nlm.nih.gov/?term=yoga+nidra"],["Wikipedia — Yoga nidra","https://en.wikipedia.org/wiki/Yoga_nidra"]]},
{id:"attention-rest",cat:"focus",ev:"mixed",title:"Увага виснажується — і відновлюється",text:"Короткі перерви, погляд удалечінь і природа відновлюють концентрацію.",body:["Спрямована увага — обмежений ресурс. Перебування на природі або хоча б погляд удалечінь дає мозку «мʼяке» відновлення, після якого легше фокусуватися.","Постійні сповіщення працюють навпаки: вони дроблять увагу й підсилюють відчуття втоми."],points:["Роби короткі перерви свідомо","Погляд удалечінь і природа відновлюють фокус","Сповіщення — головний крадій уваги"],src:[["Дослідження: природа й відновлення уваги (PubMed)","https://pubmed.ncbi.nlm.nih.gov/?term=nature+attention+restoration"],["Wikipedia — Attention restoration theory","https://en.wikipedia.org/wiki/Attention_restoration_theory"]]},
{id:"dopamine",cat:"focus",ev:"mixed",title:"Дофамін — про мотивацію, а не лише задоволення",text:"Дофамін рухає тебе до мети; постійні легкі «піки» притуплюють драйв.",body:["Дофамін більше повʼязаний з прагненням і мотивацією, ніж із самим задоволенням. Він зростає в очікуванні винагороди й штовхає до дії.","Якщо весь час підживлювати його легкими стимулами (стрічки, цукор, сповіщення), базовий драйв до складніших цілей знижується. Сталі зусилля й відпочинок від стимулів повертають чутливість."],points:["Дофамін = мотивація й прагнення","Легкі дофамінові піки притуплюють драйв","Сталість і пауза від стимулів відновлюють чутливість"],src:[["Дослідження: дофамін і мотивація (PubMed)","https://pubmed.ncbi.nlm.nih.gov/?term=dopamine+reward+motivation"],["Wikipedia — Dopamine","https://en.wikipedia.org/wiki/Dopamine"]]},
{id:"vagus",cat:"stress",ev:"mixed",title:"Блукаючий нерв і відновлення",text:"Вагус керує режимом «відпочинок і відновлення».",body:["Блукаючий нерв (вагус) — головний канал парасимпатичної системи. Його активність повʼязана зі спокоєм, травленням і відновленням.","Прості важелі впливу: повільне дихання з довгим видихом, холод на обличчя, спокійний голос і навіть наспівування — все це підвищує вагусний тонус."],points:["Вагус вмикає спокій і відновлення","Довгий видих і холод на обличчя його активують","Вищий вагусний тонус — краща стресостійкість"],src:[["Дослідження: вагус і HRV (PubMed)","https://pubmed.ncbi.nlm.nih.gov/?term=vagus+nerve+heart+rate+variability"],["Wikipedia — Vagus nerve","https://en.wikipedia.org/wiki/Vagus_nerve"]]},
{id:"hrv",cat:"stress",ev:"good",title:"HRV — вікно у нервову систему",text:"Варіабельність серцевого ритму показує гнучкість між напругою і спокоєм.",body:["HRV — це варіація інтервалів між ударами серця. Вища HRV зазвичай означає, що тіло легко перемикається між мобілізацією й відновленням.","HRV індивідуальна, тож порівнюй із собою, а не з іншими. Найбільше на неї впливають сон, дихання, рух і відновлення."],points:["Вища HRV — краща адаптивність","Порівнюй із власним базовим рівнем","Сон, дихання й рух впливають найдужче"],src:[["Дослідження: метрики й норми HRV (PubMed)","https://pubmed.ncbi.nlm.nih.gov/?term=heart+rate+variability+metrics+norms"],["Wikipedia — Heart rate variability","https://en.wikipedia.org/wiki/Heart_rate_variability"]]},
{id:"isometrics",cat:"exercise",ev:"good",title:"Ізометрія: сила без руху",text:"Статичні утримання зміцнюють мʼязи й сухожилля та вчать тримати напругу.",body:["Ізометричні утримання (планка, стілець біля стіни, вис) розвивають силу й стабільність без руху в суглобі. Вони ще й добре зміцнюють сухожилля.","Є дані, що регулярні ізометричні утримання можуть допомагати знижувати тиск у спокої. Головне — дихати рівно й не затримувати дихання під час напруги."],points:["Сила й стабільність без руху","Не затримуй дихання під час утримання","Можливий бонус для артеріального тиску"],src:[["Дослідження: ізометрія й тиск, метааналіз (PubMed)","https://pubmed.ncbi.nlm.nih.gov/?term=isometric+exercise+blood+pressure+meta-analysis"],["Wikipedia — Isometric exercise","https://en.wikipedia.org/wiki/Isometric_exercise"]]},
{id:"reading-brain",cat:"knowledge",ev:"good",title:"Читання — це тренування мозку",text:"Регулярне читання підтримує концентрацію, словник і робочу память.",body:["Читання задіює увагу, мову й уяву одночасно. Регулярна практика підтримує когнітивні навички й глибину мислення, на відміну від поверхневого гортання стрічки.","Ефект накопичувальний: навіть 10–15 хвилин на день складаються в помітний результат за місяці."],points:["Тренує увагу й мову водночас","10–15 хвилин на день — достатньо для початку","Глибше за гортання стрічки"],src:[["Дослідження: читання й когнітивні функції (PubMed)","https://pubmed.ncbi.nlm.nih.gov/?term=reading+cognitive+function"],["Wikipedia — Reading","https://en.wikipedia.org/wiki/Reading"]]},
{id:"binaural-honest",cat:"frequency",ev:"none",title:"Чесно про бінаурали та «зцілюючі частоти»",text:"Бінаурали мають лише попередню базу; «Solfeggio» і 432 Гц — традиція без доказів.",body:["Бінауральні ритми (трохи різні частоти в кожне вухо) досліджують для розслаблення й уваги, але докази поки слабкі й суперечливі.","«Solfeggio»-частоти та 432 Гц — це сучасний міф без наукового підґрунтя. Цінність прослуховування — у самому ритуалі спокою й уважності, а не в магії конкретних чисел."],points:["Бінаурали — попередні, неоднозначні дані","Solfeggio / 432 Гц — без доказів","Користь — у спокійному усвідомленому слуханні"],src:[["Дослідження: огляд бінаурал-ритмів (PubMed)","https://pubmed.ncbi.nlm.nih.gov/?term=binaural+beats+systematic+review"],["Wikipedia — Binaural beats","https://en.wikipedia.org/wiki/Binaural_beats"]]}];
