function __rsAboutRender(t){t.append(o("header",{class:"page-head"},o("button",{class:"back-link",onclick:function(){C("home")},text:"‹ Головна"}),o("p",{class:"eyebrow",text:"Resonance"}),o("h1",{class:"page-title",text:"Що таке резонанс"})));var c=o("div",{class:"card read-body"});["Резонанс — це бути в такті зі світом. Умови навколо задають ритм: холод, стрес, втома, невизначеність. Питання не в тому, щоб уникнути їх, а в тому, щоб навчитися відповідати на них спокійно й точно.","Практики тут — дихання, холод, статичні утримання, увага — це тренування адаптації. Тіло й нервова система вчаться зберігати рівновагу там, де раніше ламалися під тиском.","Ти — свій персонаж. Кожна реальна практика стає досвідом (XP) гілок розвитку, рівнями й рангами; окрема «Воля» винагороджує сталість. Прокачуєш не аватар, а себе.","Без магії й обіцянок — проста система, що тримає тебе в русі щодня й показує, як ти крок за кроком стаєш стійкішим до того, що тебе оточує."].forEach(function(p){c.append(o("p",{class:"read-text",text:p}))});t.append(c);t.append(o("button",{class:"btn primary block",onclick:function(){C("rozvytok")},text:"Перейти до Розвитку"}))}
